import React from "react";
import { Link } from "react-router-dom";

function Home() {
  return (
    <div>
      <h1>Welcome</h1>
      <p>Choose an option:</p>

      <Link to="/register">
        <button>Register</button>
      </Link>

      <span style={{ margin: "0 10px" }}></span>

      <Link to="/login">
        <button>Login</button>
      </Link>
    </div>
  );
}

export default Home;
